import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface Grade {
  subject: string;
  grade: string;
}

interface SubjectPerformance {
  subject: string;
  average: number;
}

interface GradeTrackerData {
  currentGPA: number;
  recentGrades: Grade[];
  subjectPerformance: SubjectPerformance[];
}

export default function Widget() {
  const gradeData = response.data as GradeTrackerData;
  const { currentGPA, recentGrades, subjectPerformance } = gradeData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Current GPA
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: '#4A90E2' }}>
              {currentGPA.toFixed(2)}
            </Typography>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {recentGrades.map((grade, index) => (
              <Chip
                key={index}
                label={`${grade.subject}: ${grade.grade}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: '#50E3C2', color: '#FFFFFF' }}
              />
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 120 }}>
            <BarChart
              height={120}
              series={[
                {
                  data: subjectPerformance.map(sp => sp.average),
                  color: '#4A90E2',
                },
              ]}
              xAxis={[
                {
                  data: subjectPerformance.map(sp => sp.subject),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 10,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
